    36→extension RouterParams on Request {
    37→  /// Get URL parameters captured by the [Router].
    38→  ///
    39→  /// **Example**
    40→  /// ```dart
    41→  /// final app = Router();
    42→  ///
    43→  /// app.get('/hello/<name>', (Request request) {
    44→  ///   final name = request.params['name'];
    45→  ///   return Response.ok('Hello $name');
    46→  /// });
    47→  /// ```
    48→  ///
    49→  /// If no parameters are captured this returns an empty map.
    50→  ///
    51→  /// The returned map is unmodifiable.
