    61→/// Middleware to remove body from request.
    62→final _removeBody = createMiddleware(responseHandler: (r) {
    63→  if (r.headers.containsKey('content-length')) {
    64→    r = r.change(headers: {'content-length': '0'});
    65→  }
    66→  return r.change(body: <int>[]);
