    68→
    69→/// A shelf [Router] routes requests to handlers based on HTTP verb and route
    70→/// pattern.
    71→///
    72→/// ```dart
    73→/// import 'package:shelf_router/shelf_router.dart';
    74→/// import 'package:shelf/shelf.dart';
    75→/// import 'package:shelf/shelf_io.dart' as io;
    76→///
    77→/// var app = Router();
    78→///
    79→/// // Route pattern parameters can be specified <paramName>
    80→/// app.get('/users/<userName>/whoami', (Request request) async {
    81→///   // The matched values can be read with params(request, param)
    82→///   var userName = request.params['userName'];
    83→///   return Response.ok('You are ${userName}');
    84→/// });
    85→///
    86→/// // The matched value can also be taken as parameter, if the handler given
    87→/// // doesn't implement Handler, it's assumed to take all parameters in the
    88→/// // order they appear in the route pattern.
    89→/// app.get('/users/<userName>/say-hello', (Request request, String userName) async {
    90→///   assert(userName == request.params['userName']);
    91→///   return Response.ok('Hello ${userName}');
    92→/// });
    93→///
    94→/// // It is possible to have multiple parameters, and if desired a custom
    95→/// // regular expression can be specified with <paramName|REGEXP>, where
    96→/// // REGEXP is a regular expression (leaving out ^ and $).
    97→/// // If no regular expression is specified `[^/]+` will be used.
    98→/// app.get('/users/<userName>/messages/<msgId|\d+>', (Request request) async {
    99→///   var msgId = int.parse(request.params['msgId']!);
   100→///   return Response.ok(message.getById(msgId));
   101→/// });
   102→///
   103→/// var server = await io.serve(app, 'localhost', 8080);
   104→/// ```
   105→///
   106→/// If multiple routes match the same request, the handler for the first
   107→/// route is called.
   108→/// If no route matches a request, a [Response.notFound] will be returned
   109→/// instead. The default matcher can be overridden with the `notFoundHandler`
   110→/// constructor parameter.
   111→@sealed
   112→class Router {
   113→  final List<RouterEntry> _routes = [];
   114→  final Handler _notFoundHandler;
   115→
   116→  /// Creates a new [Router] routing requests to handlers.
   117→  ///
   118→  /// The [notFoundHandler] will be invoked for requests where no matching route
   119→  /// was found. By default, a simple [Response.notFound] will be used instead.
   120→  Router({Handler notFoundHandler = _defaultNotFound})
   121→      : _notFoundHandler = notFoundHandler;
   122→
   123→  /// Add [handler] for [verb] requests to [route].
   124→  ///
   125→  /// If [verb] is `GET` the [handler] will also be called for `HEAD` requests
   126→  /// matching [route]. This is because handling `GET` requests without handling
   127→  /// `HEAD` is always wrong. To explicitely implement a `HEAD` handler it must
   128→  /// be registered before the `GET` handler.
   129→  void add(String verb, String route, Function handler) {
   130→    if (!isHttpMethod(verb)) {
   131→      throw ArgumentError.value(verb, 'verb', 'expected a valid HTTP method');
   132→    }
   133→    verb = verb.toUpperCase();
   134→
   135→    if (verb == 'GET') {
   136→      // Handling in a 'GET' request without handling a 'HEAD' request is always
   137→      // wrong, thus, we add a default implementation that discards the body.
   138→      _routes.add(RouterEntry('HEAD', route, handler, middleware: _removeBody));
   139→    }
   140→    _routes.add(RouterEntry(verb, route, handler));
   141→  }
   142→
   143→  /// Handle all request to [route] using [handler].
   144→  void all(String route, Function handler) {
   145→    _routes.add(RouterEntry('ALL', route, handler));
   146→  }
   147→
   148→  /// Mount a handler below a prefix.
   149→  ///
   150→  /// In this case prefix may not contain any parameters, nor
   151→  void mount(String prefix, Handler handler) {
   152→    if (!prefix.startsWith('/')) {
   153→      throw ArgumentError.value(prefix, 'prefix', 'must start with a slash');
   154→    }
   155→
   156→    // first slash is always in request.handlerPath
   157→    final path = prefix.substring(1);
   158→    if (prefix.endsWith('/')) {
   159→      all('$prefix<path|[^]*>', (Request request) {
   160→        return handler(request.change(path: path));
   161→      });
   162→    } else {
   163→      all(prefix, (Request request) {
   164→        return handler(request.change(path: path));
   165→      });
   166→      all('$prefix/<path|[^]*>', (Request request) {
   167→        return handler(request.change(path: '$path/'));
   168→      });
   169→    }
   170→  }
   171→
   172→  /// Route incoming requests to registered handlers.
   173→  ///
   174→  /// This method allows a Router instance to be a [Handler].
   175→  Future<Response> call(Request request) async {
   176→    // Note: this is a great place to optimize the implementation by building
   177→    //       a trie for faster matching... left as an exercise for the reader :)
   178→    for (var route in _routes) {
   179→      if (route.verb != request.method.toUpperCase() && route.verb != 'ALL') {
   180→        continue;
   181→      }
   182→      var params = route.match('/${request.url.path}');
   183→      if (params != null) {
   184→        final response = await route.invoke(request, params);
   185→        if (response != routeNotFound) {
   186→          return response;
   187→        }
   188→      }
   189→    }
   190→    return _notFoundHandler(request);
   191→  }
   192→
   193→  // Handlers for all methods
   194→
   195→  /// Handle `GET` request to [route] using [handler].
   196→  ///
   197→  /// If no matching handler for `HEAD` requests is registered, such requests
   198→  /// will also be routed to the [handler] registered here.
   199→  void get(String route, Function handler) => add('GET', route, handler);
   200→
   201→  /// Handle `HEAD` request to [route] using [handler].
   202→  void head(String route, Function handler) => add('HEAD', route, handler);
   203→
   204→  /// Handle `POST` request to [route] using [handler].
   205→  void post(String route, Function handler) => add('POST', route, handler);
   206→
   207→  /// Handle `PUT` request to [route] using [handler].
   208→  void put(String route, Function handler) => add('PUT', route, handler);
   209→
   210→  /// Handle `DELETE` request to [route] using [handler].
   211→  void delete(String route, Function handler) => add('DELETE', route, handler);
   212→
   213→  /// Handle `CONNECT` request to [route] using [handler].
   214→  void connect(String route, Function handler) =>
   215→      add('CONNECT', route, handler);
   216→
   217→  /// Handle `OPTIONS` request to [route] using [handler].
   218→  void options(String route, Function handler) =>
   219→      add('OPTIONS', route, handler);
   220→
   221→  /// Handle `TRACE` request to [route] using [handler].
   222→  void trace(String route, Function handler) => add('TRACE', route, handler);
   223→
   224→  /// Handle `PATCH` request to [route] using [handler].
   225→  void patch(String route, Function handler) => add('PATCH', route, handler);
   226→
   227→  static Response _defaultNotFound(Request request) => routeNotFound;
   228→
   229→  /// Sentinel [Response] object indicating that no matching route was found.
   230→  ///
   231→  /// This is the default response value from a [Router] created without a
   232→  /// `notFoundHandler`, when no routes matches the incoming request.
   233→  ///
   234→  /// If the [routeNotFound] object is returned from a [Handler] the [Router]
   235→  /// will consider the route _not matched_, and attempt to match other routes.
   236→  /// This is useful when mounting nested routers, or when matching a route
   237→  /// is conditioned on properties beyond the path of the URL.
   238→  ///
   239→  /// **Example**
   240→  /// ```dart
   241→  /// final app = Router();
   242→  ///
   243→  /// // The pattern for this route will match '/search' and '/search?q=...',
   244→  /// // but if request does not have `?q=...', then the handler will return
   245→  /// // [Router.routeNotFound] causing the router to attempt further routes.
   246→  /// app.get('/search', (Request request) async {
   247→  ///   if (!request.uri.queryParameters.containsKey('q')) {
   248→  ///     return Router.routeNotFound;
   249→  ///   }
   250→  ///   return Response.ok('TODO: make search results');
   251→  /// });
   252→  ///
   253→  /// // Same pattern as above
   254→  /// app.get('/search', (Request request) async {
   255→  ///   return Response.ok('TODO: return search form');
   256→  /// });
   257→  ///
   258→  /// // Create a single nested router we can mount for handling API requests.
   259→  /// final api = Router();
   260→  ///
   261→  /// api.get('/version', (Request request) => Response.ok('1'));
   262→  ///
   263→  /// // Mounting router under '/api'
   264→  /// app.mount('/api', api);
   265→  ///
   266→  /// // If a request matches `/api/...` then the routes in the [api] router
   267→  /// // will be attempted. However, for a request like `/api/hello` there is
   268→  /// // no matching route in the [api] router. Thus, the router will return
   269→  /// // [Router.routeNotFound], which will cause matching to continue.
   270→  /// // Hence, the catch-all route below will be matched, causing a custom 404
   271→  /// // response with message 'nothing found'.
   272→  ///
   273→  /// // In the pattern below `<anything|.*>` is on the form `<name|regex>`,
   274→  /// // thus, this simply creates a URL parameter called `anything` which
   275→  /// // matches anything.
   276→  /// app.all('/<anything|.*>', (Request request) {
   277→  ///   return Response.notFound('nothing found');
   278→  /// });
   279→  /// ```
   280→  static final Response routeNotFound = _RouteNotFoundResponse();
   281→}
   282→
   283→/// Extends [Response] to allow it to be used multiple times in the
   284→/// actual content being served.
   285→class _RouteNotFoundResponse extends Response {
   286→  static const _message = 'Route not found';
   287→  static final _messageBytes = utf8.encode(_message);
   288→
   289→  _RouteNotFoundResponse() : super.notFound(_message);
   290→
   291→  @override
   292→  Stream<List<int>> read() => Stream<List<int>>.value(_messageBytes);
   293→
   294→  @override
   295→  Response change({
   296→    Map<String, /* String | List<String> */ Object?>? headers,
   297→    Map<String, Object?>? context,
   298→    Object? body,
   299→  }) {
   300→    return super.change(
   301→      headers: headers,
   302→      context: context,
   303→      body: body ?? _message,
   304→    );
   305→  }
   306→}
   307→

