    final b1 = await Router.routeNotFound.readAsString();
    expect(b1, 'Route not found');
    final b2 = await Router.routeNotFound.readAsString();
    expect(b2, b1);
  });

  test('HEAD request preserves content-length from GET', () async {
    var app = Router();

    app.get('/hello', (Request request) {
      // Explicitly set content-length header
      return Response.ok('hello-world',
          headers: {'content-length': '11'});
    });

    server.mount(app.call);

    // Get the response body length from GET request
    final getBody = await get('/hello');
    expect(getBody, 'hello-world');

    // Get the content-length header from HEAD request
    final headResp = await getHeadResponse('/hello');
    expect(headResp.statusCode, 200);

    // The content-length should NOT be '0'
    expect(headResp.headers['content-length'], isNotEmpty);
    expect(headResp.headers['content-length'], isNot('0'));
    // It should be '11' (the original length)
    expect(headResp.headers['content-length'], '11');
  });
}

