    var api = Router(notFoundHandler: (req) => Response.ok('Not found, but ok'))
      ..get('/hello', (request) => Response.ok('Hello'));
    server.mount(api.call);

    expect(get('/hi'), completion('Not found, but ok'));
  });

  test('can call Router.routeNotFound.read multiple times', () async {
    final b1 = await Router.routeNotFound.readAsString();
    expect(b1, 'Route not found');
    final b2 = await Router.routeNotFound.readAsString();
    expect(b2, b1);
  });

  test('HEAD request does not modify content-length header', () async {
    var app = Router();

    app.get('/hello', (Request request) {
      // Explicitly set content-length header
      return Response.ok('hello-world',
          headers: {'content-length': '11'});
    });

    // Test directly without HTTP layer
    final getRequest = Request('GET', Uri.parse('http://localhost/hello'));
    final headRequest = Request('HEAD', Uri.parse('http://localhost/hello'));

    final getResponse = await app(getRequest);
    final headResponse = await app(headRequest);

    print('GET response headers: ${getResponse.headers}');
    print('HEAD response headers: ${headResponse.headers}');

    expect(getResponse.statusCode, 200);
    expect(headResponse.statusCode, 200);

