    final headRequest = Request('HEAD', Uri.parse('http://localhost/hello'));

    // The router should apply the _removeBody middleware which currently sets content-length to '0'
    final headResponse = await app(headRequest);

    print('HEAD response content-length: ${headResponse.headers['content-length']}');
    print('HEAD response body: "${await headResponse.readAsString()}"');

    // This test will FAIL if the middleware is working (content-length == '0')
    // and PASS if the middleware is not applied (content-length == '11')
    // The expected behavior per RFC 9110 is that content-length should be '11'
    expect(headResponse.headers['content-length'], '11',
        reason: 'RFC 9110 Section 9.3.2: HEAD response should have same content-length as GET');
  });
}

